const staggerContainerSlow: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.15 } },
};

const VP = { once: true, margin: "-80px" };

// ---------------------------------------------------------------------------
// Value props — 5 items for horizontal strip
// ---------------------------------------------------------------------------
const VALUE_PROPS = [
  { id: "ai", label: "AI-Powered Valuation", Icon: Sparkles },
  { id: "payout", label: "Fast Cash or Crypto Payouts", Icon: Zap },
  { id: "nocheck", label: "No Credit Check or Paper Work", Icon: ShieldCheck },
  { id: "insured", label: "Fully-Insured Shipping", Icon: Package },
  { id: "storage", label: "Secure Storage", Icon: Lock },
] as const;

// ---------------------------------------------------------------------------
// Gallery images — 5 photos
// ---------------------------------------------------------------------------

// ---------------------------------------------------------------------------
// Hero request card — shows the user's last buyback request
// ---------------------------------------------------------------------------
function HeroRequestCard({ request }: { request: BuybackRequestListItem }) {
  const { buyback } = request;
  const mainPhoto =
    buyback.asset.meta?.photos?.main ?? buyback.asset.photos?.[0];
  const itemName =
    `${buyback.asset.brand?.name ?? ""} ${buyback.asset.model?.name ?? ""}`.trim();

  return (
    <Link
      className="flex items-stretch gap-5 overflow-clip transition-opacity hover:opacity-80"
      href={APP_ROUTES.BUYBACK_REQUESTS.DETAIL(request.id)}
    >
      {/* Square image — 152×152 */}
      <div className="relative h-[152px] w-[152px] shrink-0 overflow-hidden rounded-[4px]">
        {mainPhoto ? (
          <Image
            alt={itemName || "Luxury item"}
            className="object-cover"
            fill
            sizes="152px"
            src={getCdnUrl(mainPhoto)}
          />
        ) : (
          <div className="flex h-full w-full items-center justify-center bg-white/10">
            <Image
              alt=""
              className="opacity-40"
              height={48}
              src="/new-design-images/icons/watch-icon.svg"
              width={48}
            />
          </div>
        )}
      </div>

      {/* Text */}
      <div className="flex w-[278px] flex-col justify-between overflow-hidden">
        <p className="font-new-sans text-[#F5F3EF]/70 text-sm italic">
          Recently Quoted
        </p>

        {/* 3-segment progress divider */}
        <div className="flex items-center gap-1.5 py-2">
          <div className="relative h-px flex-1 overflow-hidden">
            <div className="absolute inset-[-1px] bg-white" />
          </div>
          <div className="relative h-px flex-1 overflow-hidden border-[0.5px] border-white/40">
            <div className="absolute inset-[-1px_73%_-1px_-1px] bg-white" />
          </div>
          <div className="h-px flex-1 border-[0.5px] border-white/40" />
        </div>

        <div className="flex flex-col gap-0.5">
          <p className="line-clamp-2 font-medium font-new-sans text-[#F5F3EF] text-base leading-normal">
            {itemName}
          </p>
          <p className="font-extralight font-new-serif text-2xl text-[#F5F3EF] leading-[1.2]">
            {getStatusLabel(request.status)}
          </p>
        </div>
      </div>
    </Link>
  );
}

// ---------------------------------------------------------------------------
// Hero headline — word-by-word reveal
// ---------------------------------------------------------------------------
function AnimatedHeadline({
  text,
  className,
}: {
  text: string;
  className?: string;
}) {
  const words = text.split(" ");
  return (
    <motion.h1
      animate="visible"
      className={className}
      initial="hidden"
      variants={staggerContainer}
    >
      {words.map((word, idx) => (
        <motion.span
          // eslint-disable-next-line react/no-array-index-key
          className="inline-block"
          key={`word-${idx}`}
          variants={{
            hidden: { opacity: 0, y: 40, rotateX: -15 },
            visible: {
              opacity: 1,
              y: 0,
              rotateX: 0,
              transition: { duration: 0.7, ease: [0.22, 1, 0.36, 1] },
            },
          }}
        >
          {word}
          {idx < words.length - 1 ? "\u00A0" : ""}
        </motion.span>
      ))}
    </motion.h1>
  );
}

// ---------------------------------------------------------------------------
// Steps section — Lottie + synced progress bars
// ---------------------------------------------------------------------------
function StepsSection() {
  const router = useRouter();
  const [activeStep, setActiveStep] = useState(0);
  const [liveProgress, setLiveProgress] = useState(0);
  const activeStepRef = useRef(0);

  const handleDotLottieRef = useCallback((dl: DotLottie | null) => {
    if (!dl) return;

    dl.addEventListener("frame", () => {
      if (dl.totalFrames > 0) {
        setLiveProgress(dl.currentFrame / dl.totalFrames);
      }
    });

    dl.addEventListener("complete", () => {
      const next = (activeStepRef.current + 1) % 4;
      activeStepRef.current = next;
      setActiveStep(next);
      setLiveProgress(0);
    });
  }, []);

  return (
    <section className="overflow-hidden bg-background">
      <div className="flex flex-col min-[1172px]:flex-row min-[1172px]:items-stretch">
        {/* Left — dark damask panel with iPhone */}
        <div className="relative flex items-center justify-center overflow-hidden bg-[#020A3A] px-6 py-16 min-[1172px]:w-[50%] min-[1172px]:shrink-0 min-[1172px]:py-24">
          {/* Damask background image */}
          <Image
            alt="Steps background"
            aria-hidden="true"
            className="pointer-events-none object-cover opacity-60"
            fill
            sizes="50vw"
            src="/new-design-images/steps-bg.webp"
          />
          {/* Lottie inside iPhone mockup */}
          <motion.div
            className="relative z-10"
            initial="hidden"
            variants={slideLeft}
            viewport={VP}
            whileInView="visible"
          >
            <div
              className="relative w-[240px] min-[1172px]:w-[320px]"
              style={{ aspectRatio: "740 / 1500" }}
            >
              {/* Lottie clipped to screen — overflow-hidden + rounded clips corners & background */}
              <div className="absolute inset-[2%_4%] overflow-hidden rounded-[12%]">
                <DotLottieReact
                  autoplay
                  dotLottieRefCallback={handleDotLottieRef}
                  key={activeStep}
                  loop={false}
                  src={`/lottie/Scene-${activeStep + 1}.lottie`}
                  style={{ width: "100%", height: "100%" }}
                />
              </div>
              {/* iPhone frame on top */}
              <Image
                alt="LuxFlow mobile app"
                className="pointer-events-none z-10 object-contain"
                fill

                sizes="320px"
                src="/new-design-images/iphone-mockup.png"
              />
            </div>
          </motion.div>
        </div>

        {/* Right — steps list */}
        <div className="flex flex-1 flex-col gap-8 bg-[#F5F3EF] px-10 py-16">
          <motion.h2
            className="font-extralight font-new-serif text-3xl leading-[1.2] min-[1172px]:text-[44px]"
            initial="hidden"
            variants={fadeUp}
            viewport={VP}
            whileInView="visible"
          >
            Get Instant Cash
            <br />
            in 4 Simple Steps
          </motion.h2>

          <div className="flex flex-col">
            {LANDING_STEPS.map((step, index) => {
              let barWidth = "0%";
              if (index < activeStep) {
                barWidth = "100%";
              } else if (index === activeStep) {
                barWidth = `${liveProgress * 100}%`;
              }

              return (
                <motion.div
                  className="flex flex-col gap-3 border-[#D6D3D1] border-t py-5 first:border-t-0 first:pt-0"
                  initial="hidden"
                  key={step.number}
                  transition={{ delay: index * 0.08 }}
                  variants={fadeUp}
                  viewport={VP}
                  whileInView="visible"
                >
                  <div className="flex items-start justify-between gap-4">
                    <h3
                      className={
                        "font-extralight font-new-serif text-[24px] leading-[1.2] transition-colors min-[1172px]:text-[30px]"
                      }
                    >
                      {index + 1}. {step.title}
                    </h3>
                  </div>
                  <p className="font-new-sans text-sm leading-relaxed">
                    {step.description}
                  </p>
                  {/* Progress bar — driven by Lottie frame*/}
                  <div className="relative h-[2px] w-full overflow-hidden bg-[#D6D3D1]">
                    <div
                      className="absolute inset-y-0 left-0 bg-[#001A8C] transition-none"
                      style={{ width: barWidth }}
                    />
                  </div>
                </motion.div>
              );
            })}
          </div>

          <motion.div
            className="w-fit"
            initial="hidden"
            variants={fadeUp}
            viewport={VP}
            whileHover={{ scale: 1.03 }}
            whileInView="visible"
            whileTap={{ scale: 0.97 }}
          >
            <Button
              className="rounded-sm"
              onClick={() => {
                router.push(APP_ROUTES.BUYBACK_REQUESTS.CREATE);
              }}
            >
              Start with a Quote
              <span aria-hidden="true">→</span>
            </Button>
          </motion.div>
        </div>
      </div>
    </section>
  );
}

const LANDING_TRUST_FEATURES = [
  {
    title: "Discreet and Private",
    description: "Transactions are 100% confidential. No public offers.",
  },
  {
    title: "Fast AI-Driven. Expert-Led Valuation",
    description:
      "We use both manual inspection and AI-driven tech, including devices like Entrupy, to verify material, craftsmanship, serials, and more; for an accurate final offer.",
  },
  {
    title: "Insured Custody & Delivery",
    description:
      "We partner with Brink's to deliver fully insured pickup, plus insured high-security vaults managed to storage and protect your values.",
  },
  {
    title: "Same-Day Payout",
    description: "Get paid via bank deposits, PayPal, or stablecoins.",
  },
];

export default function TrustSection() {
  return (
    <section className="relative flex min-h-[858px] w-full items-center justify-center overflow-hidden bg-[#0A0A0B] py-20 text-background">
      {/* Background Video & Overlay */}
      <div className="absolute inset-0 z-0">
        <video
          autoPlay
          className="h-full w-full object-cover opacity-40"
          loop
          muted
          playsInline
        >
